body.raw:
{
  "json": {
    "siteId": "{{siteId}}",
    "key": "postman_station_summary",
    "label": "Postman Station Summary",
    "description": "Site-authored graph type example.",
    "inputs": [
      {
        "key": "stationId",
        "label": "Station",
        "description": "Station backing this node.",
        "valueType": "entityRef",
        "entityKey": "imm.station",
        "required": true,
        "sortOrder": 10
      }
    ],
    "facets": [
      {
        "key": "workcenterId",
        "label": "Workcenter",
        "valueType": "string",
        "resolverType": "entity",
        "resolver": {
          "type": "entity",
          "entityRef": {
            "key": "imm.station",
            "id": "$input.stationId"
          },
          "path": "workcenter"
        },
        "sortOrder": 10
      }
    ],
    "fields": [
      {
        "key": "goodItems",
        "label": "Good Items",
        "valueType": "number",
        "resolverType": "metric",
        "resolver": {
          "type": "metric",
          "entityType": "STATION",
          "entityId": "$input.stationId",
          "granularity": "SHIFT",
          "metricKey": "goodItems"
        },
        "sortOrder": 10
      }
    ]
  }
}
